static char *build_command(const char *user) {
    for (const unsigned char *p = (const unsigned char *)user; *p; ++p) {
        if (!((*p >= 'a' && *p <= 'z') ||
              (*p >= 'A' && *p <= 'Z') ||
              (*p >= '0' && *p <= '9') ||
              *p == '_' || *p == '-')) {
            return NULL;
        }
    }

    char *cmd = NULL;
    size_t len = strlen(user) + 32;

    cmd = malloc(len);
    if (!cmd) {
        return NULL;
    }

    strcpy(cmd, "id ");
    strcat(cmd, user);

    return cmd;
}
